package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.Nado; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Peixe; public class PeixeMorcego extends Peixe implements Nado { public PeixeMorcego(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " não emite som audível para humanos."); } public void comer() { System.out.println(getNome() + " está comendo pequenos invertebrados."); } public void nadar() { System.out.println(getNome() + " está nadando próximo ao fundo do mar."); } }
